mapper.select:
SELECT PRG_NUM, USER_NUM, CLA_NUM, LSN_NUM, PRG_COMPLETE, PRG_LASTDATE
FROM PROGRESS
WHERE USER_NUM = #{userNum} AND CLA_NUM = #{claNum}

mapper.insert:
INSERT INTO PROGRESS (PRG_NUM, USER_NUM, CLA_NUM, LSN_NUM, PRG_COMPLETE, PRG_LASTDATE) SELECT SEQ_PRG.NEXTVAL, #{userNum}, #{claNum}, LSN_NUM, 'N', SYSDATE
FROM LESSON
WHERE CLA_NUM = #{claNum}

mapper.update:
UPDATE PROGRESS
SET PRG_COMPLETE = 'Y', PRG_LASTDATE = SYSDATE
WHERE USER_NUM = #{userNum} AND LSN_NUM = #{lsnNum}
